mapper.select:
select di.id as instanceId, di.template_id as templateId, di.aircraft_id as aircraftId, di.current_version_id as currentVersionId, di.current_version_no as currentVersionNo, di.instance_label as instanceLabel, di.status as instanceStatus, di.updated_at as instanceUpdatedAt, pa.tail_number as tailNumber, pa.msn, pa.registration_number as registrationNumber, pa.aircraft_type as aircraftType, pa.variant, pa.engine_type as engineType, pa.manufacturer, pa.delivery_date as deliveryDate, pa.operational_status as operationalStatus, pa.total_fh as totalFh, pa.total_fc as totalFc, pa.current_operator as currentOperator, am.model_code as modelCode, am.name as modelName, dt.template_code as templateCode, dt.template_version as templateVersion, dt.name as templateName from t1_dossier_instance di left join t1_physical_aircraft pa on pa.id = di.aircraft_id left join t1_ac_model am on am.id = pa.model_id left join t1_dossier_template dt on dt.id = di.template_id
di.deleted_at is null
and di.id = #{instanceId}
and di.aircraft_id = #{aircraftId}
order by case when pa.tail_number = 'B-1234' then 0 else 1 end, case when di.status in ('ready','published') then 0 else 1 end, di.updated_at desc limit 1

select dv.id as versionId, dv.dossier_instance_id as instanceId, dv.template_id as templateId, dv.template_code as templateCode, dv.template_version as templateVersion, dv.version_no as versionNo, dv.version_label as versionLabel, dv.major_version_no as majorVersionNo, dv.minor_version_no as minorVersionNo, dv.version_level as versionLevel, dv.previous_version_id as previousVersionId, dv.generation_job_id as generationJobId, dv.data_snapshot_id as dataSnapshotId, dv.version_reason as versionReason, dv.is_current as isCurrent, dv.change_summary as changeSummary, cast(dv.content_summary_json as char) as contentSummaryJson, cast(dv.generation_params_json as char) as generationParamsJson, dv.created_by as createdBy, dv.created_at as createdAt, dv.published_at as publishedAt, gj.job_code as jobCode, gj.job_status as jobStatus, gj.progress_percent as progressPercent, cast(gj.output_json as char) as outputJson, ds.snapshot_code as snapshotCode from t1_dossier_version dv left join t1_generation_job gj on gj.id = dv.generation_job_id left join t1_data_snapshot ds on ds.id = dv.data_snapshot_id where dv.dossier_instance_id = #{instanceId}
and dv.id = #{versionId}
order by case when dv.is_current = 1 then 0 else 1 end, dv.version_no desc limit 1

select id as contentItemId, structure_node_id as structureNodeId, item_code as itemCode, item_name as itemName, item_type as itemType, lifecycle_stage as lifecycleStage, aircraft_id as aircraftId, bom_node_id as bomNodeId, part_instance_id as partInstanceId, is_key_part as isKeyPart, supply_mode as supplyMode, source_system as sourceSystem, source_table as sourceTable, source_record_key as sourceRecordKey, completeness_status as completenessStatus, content_summary as contentSummary, file_storage_key as fileStorageKey, cast(source_trace_json as char) as sourceTraceJson, cast(attrs_json as char) as attrsJson from t1_dossier_content_item where dossier_version_id = #{versionId}
and bom_node_id = #{bomNodeId}
order by sort_order, item_code

select id as documentEntryId, structure_node_id as structureNodeId, doc_no as docNo, title, file_storage_key as fileStorageKey, source_system as sourceSystem, source_table as sourceTable, source_record_key as sourceRecordKey, document_status as documentStatus, completeness_status as completenessStatus, required_flag as requiredFlag, included_flag as includedFlag, cast(source_trace_json as char) as sourceTraceJson, cast(attrs_json as char) as attrsJson from t1_document_entry where dossier_version_id = #{versionId}
and structure_node_id = #{structureNodeId}
order by required_flag desc, title

select id as operationLogId, operation_type as operationType, operation_name as operationName, operation_status as operationStatus, business_subject_type as businessSubjectType, business_subject_id as businessSubjectId, operator_name as operatorName, result_message as resultMessage, operated_at as operatedAt, cast(detail_json as char) as detailJson from t1_dossier_operation_log where dossier_instance_id = #{instanceId}
and (dossier_version_id = #{versionId} or dossier_version_id is null)
order by operated_at desc limit 20
